"use client";

import React, { useRef, useEffect, useState } from "react";
import { motion, useAnimation, useMotionValue, animate, Variants } from "framer-motion";
import { cn } from "@/components/lib/utils";
import Image from "next/image";

interface AngledSliderProps {
    /**
     * Array of image objects or URLs
     */
    items: {
        id: string | number;
        url: string;
        alt?: string;
        title?: string;
    }[];
    /**
     * Speed of auto-scroll (seconds for full loop). Higher is slower.
     * @default 20
     */
    speed?: number;
    /**
     * Direction of scroll
     * @default "left"
     */
    direction?: "left" | "right";
    /**
     * Height of the slider container
     * @default "400px"
     */
    containerHeight?: string;
    /**
     * Width of each card
     * @default "300px"
     */
    cardWidth?: string;
    /**
     * Gap between cards
     * @default "40px"
     */
    gap?: string;
    /**
     * Angle of the 3D skew/rotation
     * @default 20
     */
    angle?: number;
    /**
     * Scale on hover
     * @default 1.05
     */
    hoverScale?: number;
    className?: string;
}

const cardVariants: Variants = {
    offHover: (angle: number) => ({
        rotateY: angle,
        z: 60, // Ensure card is in front of container plane (which blocks -Z events)
        opacity: 0.9,
        scale: 1,
        zIndex: 30, // Higher than potential overlays
        transition: {
            type: "spring",
            mass: 3,
            stiffness: 400,
            damping: 50
        }
    }),
    onHover: (hoverScale: number) => ({
        rotateY: 0,
        z: 120, // Pop out further
        opacity: 1,
        scale: hoverScale,
        zIndex: 50,
        transition: {
            type: "spring",
            mass: 3,
            stiffness: 400,
            damping: 50
        }
    })
};

const AngledCard = ({
    item,
    angle,
    hoverScale,
    cardWidth
}: {
    item: any;
    angle: number;
    hoverScale: number;
    cardWidth: string;
}) => {
    const [isHovered, setIsHovered] = useState(false);

    return (
        <motion.div
            className="relative flex-shrink-0 group overflow-visible cursor-pointer"
            style={{
                width: cardWidth,
                height: "100%",
                transformStyle: "preserve-3d",
            }}
            custom={isHovered ? hoverScale : angle}
            variants={cardVariants}
            initial="offHover"
            animate={isHovered ? "onHover" : "offHover"}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
        >
            {/* The Image Card */}
            <div className="relative h-full w-full overflow-hidden border border-white/10 bg-muted 
            min-h-[300px] shadow-2xl">
                <Image
                    src={item.url}
                    alt={item.alt || "Slider Image"}
                    fill
                    className="object-cover transition-transform duration-500 group-hover:scale-110"
                />
                {/* Optional Overlay/Title */}
                {item.title && (
                    <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/80 to-transparent p-4 text-white opacity-0 transition-opacity duration-300 group-hover:opacity-100">
                        <h3 className="text-lg font-bold">{item.title}</h3>
                    </div>
                )}
            </div>
        </motion.div>
    );
};

export const AngledSlider = ({
    items,
    speed = 40,
    direction = "left",
    containerHeight = "400px",
    cardWidth = "300px",
    gap = "40px",
    angle = 20,
    hoverScale = 1.05,
    className,
}: AngledSliderProps) => {
    const [width, setWidth] = useState(0);
    const containerRef = useRef<HTMLDivElement>(null);

    const x = useMotionValue(0);
    const [isHovered, setIsHovered] = useState(false);

    // Duplicate items for infinite loop effect
    // We need enough duplicates to fill the screen + buffer
    const duplicatedItems = [...items, ...items, ...items];

    useEffect(() => {
        const calculateWidth = () => {
            // Fallback to prop-based calculation if ref is not quite ready or layout is shifting
            // This is generally safer for known fixed-width items
            const numWidth = parseInt(cardWidth?.toString().replace("px", "") || "300");
            const numGap = parseInt(gap?.toString().replace("px", "") || "40");

            if (!isNaN(numWidth) && !isNaN(numGap)) {
                const calculatedWidth = (numWidth + numGap) * items.length;
                setWidth(calculatedWidth);
            } else if (containerRef.current) {
                const scrollWidth = containerRef.current.scrollWidth;
                setWidth(scrollWidth / 3);
            }
        };

        calculateWidth();
        window.addEventListener('resize', calculateWidth);
        return () => window.removeEventListener('resize', calculateWidth);
    }, [items, cardWidth, gap]);

    useEffect(() => {
        if (width <= 0) return;

        const startX = direction === "left" ? 0 : -width;
        const endX = direction === "left" ? -width : 0;

        if (isHovered) return;

        const runAnimation = () => {
            const currentX = x.get();
            const totalDist = width;
            const dist = Math.abs(endX - currentX);
            const duration = speed * (dist / totalDist);

            const controls = animate(x, endX, {
                duration: duration,
                ease: "linear",
                onComplete: () => {
                    x.set(startX);
                    runAnimation();
                }
            });
            return controls;
        };

        const animation = runAnimation();

        return () => {
            animation.stop();
        };
    }, [width, speed, direction, isHovered, x]);

    return (
        <div
            className={cn(
                "relative w-full overflow-hidden bg-background py-10 perspective-1000",
                className
            )}
            style={{
                height: containerHeight,
                perspective: "1000px", // Essential for 3D effect
            }}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
        >


            <motion.div
                ref={containerRef}
                className="flex items-center"
                style={{ x, gap, transformStyle: "preserve-3d" }}

            >
                {duplicatedItems.map((item, index) => (
                    <AngledCard
                        key={`${item.id}-${index}`}
                        item={item}
                        angle={angle}
                        hoverScale={hoverScale}
                        cardWidth={cardWidth}
                    />
                ))}
            </motion.div>
        </div>
    );
};

"use client";

import React, {
  useEffect,
  useRef,
  useCallback,
  useState,
} from "react";
import { cn } from "@/components/lib/utils";

// ─── Types ──────────────────────────────────────────────────────────────────

interface Bubble {
  x: number;
  y: number;
  vx: number;
  vy: number;
  radius: number;
  baseRadius: number;
  opacity: number;
  color: string;
  hue: number;
  phase: number;      // sin-wave phase for wobble
  wobble: number;     // horizontal oscillation amplitude
  depth: number;      // 0 (far) → 1 (close) — controls size & opacity
  glowIntensity: number;
  shimmerOffset: number;
  life: number;       // 0-1, decreases as bubble rises
  popped: boolean;
  popProgress: number;
}

export interface AnimatedBubbleParticlesProps {
  className?: string;
  /** Primary gradient color (hue start, 0-360) */
  colorHueStart?: number;
  /** Secondary gradient color (hue end, 0-360) */
  colorHueEnd?: number;
  /** Saturation of bubble colors (0-100) */
  saturation?: number;
  /** Lightness of bubble colors (0-100) */
  lightness?: number;
  /** Max number of simultaneous bubbles */
  maxBubbles?: number;
  /** Bubble spawn rate in ms */
  spawnInterval?: number;
  /** Min bubble radius in px */
  minRadius?: number;
  /** Max bubble radius in px */
  maxRadius?: number;
  /** Rise speed multiplier */
  speed?: number;
  /** Mouse push repulsion radius */
  mouseRepelRadius?: number;
  /** Enable mouse interaction */
  mouseInteraction?: boolean;
  /** Enable glow effect */
  enableGlow?: boolean;
  /** Enable pop animation on click */
  enablePop?: boolean;
  /** Background color (CSS value) */
  backgroundColor?: string;
  /** Z-index of the canvas layer */
  zIndex?: number;
  children?: React.ReactNode;
}

// ─── Helpers ────────────────────────────────────────────────────────────────

const lerp = (a: number, b: number, t: number) => a + (b - a) * t;
const clamp = (v: number, lo: number, hi: number) =>
  Math.max(lo, Math.min(hi, v));
const rand = (min: number, max: number) => min + Math.random() * (max - min);

function createBubble(
  w: number,
  h: number,
  hueStart: number,
  hueEnd: number,
  sat: number,
  lit: number,
  minR: number,
  maxR: number
): Bubble {
  const depth = rand(0.15, 1);
  const baseRadius = lerp(minR, maxR, depth) * rand(0.7, 1.3);
  const hue = rand(hueStart, hueEnd);
  return {
    x: rand(baseRadius, w - baseRadius),
    y: h + baseRadius + rand(0, 80),
    vx: rand(-0.4, 0.4),
    vy: -rand(0.5, 1.8) * (0.4 + depth * 0.8),
    radius: baseRadius,
    baseRadius,
    opacity: rand(0.25, 0.7) * depth,
    color: `hsl(${hue}, ${sat}%, ${lit}%)`,
    hue,
    phase: rand(0, Math.PI * 2),
    wobble: rand(8, 40) * (1 - depth * 0.6),
    depth,
    glowIntensity: rand(6, 22) * depth,
    shimmerOffset: rand(0, Math.PI * 2),
    life: 1,
    popped: false,
    popProgress: 0,
  };
}

// ─── Component ──────────────────────────────────────────────────────────────

const AnimatedBubbleParticles: React.FC<AnimatedBubbleParticlesProps> = ({
  className,
  colorHueStart = 200,
  colorHueEnd = 260,
  saturation = 80,
  lightness = 65,
  maxBubbles = 55,
  spawnInterval = 280,
  minRadius = 8,
  maxRadius = 55,
  speed = 1,
  mouseRepelRadius = 120,
  mouseInteraction = true,
  enableGlow = true,
  enablePop = true,
  backgroundColor = "transparent",
  zIndex = 0,
  children,
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const bubblesRef = useRef<Bubble[]>([]);
  const mouseRef = useRef({ x: -9999, y: -9999, active: false });
  const rafRef = useRef<number>(0);
  const lastSpawnRef = useRef<number>(0);
  const [dims, setDims] = useState({ w: 0, h: 0 });

  // ── Resize ──────────────────────────────────────────────────────────────
  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const updateSize = () => {
      const w = container.clientWidth || container.offsetWidth || (typeof window !== "undefined" ? window.innerWidth : 0);
      const h = container.clientHeight || container.offsetHeight || (typeof window !== "undefined" ? window.innerHeight : 0);
      if (w > 0 && h > 0) {
        setDims({ w, h });
        if (canvasRef.current) {
          canvasRef.current.width = w;
          canvasRef.current.height = h;
        }
      }
    };

    // Initial check
    updateSize();

    const ro = new ResizeObserver((entries) => {
      for (const e of entries) {
        const { width, height } = e.contentRect;
        const w = Math.round(width) || container.clientWidth || container.offsetWidth;
        const h = Math.round(height) || container.clientHeight || container.offsetHeight;
        if (w > 0 && h > 0) {
          setDims({ w, h });
          if (canvasRef.current) {
            canvasRef.current.width = w;
            canvasRef.current.height = h;
          }
        }
      }
    });
    ro.observe(container);
    if (typeof window !== "undefined") {
      window.addEventListener("resize", updateSize);
    }

    return () => {
      ro.disconnect();
      if (typeof window !== "undefined") {
        window.removeEventListener("resize", updateSize);
      }
    };
  }, []);

  // ── Mouse ────────────────────────────────────────────────────────────────
  useEffect(() => {
    if (!mouseInteraction) return;
    const container = containerRef.current;
    if (!container) return;

    const onMove = (e: MouseEvent) => {
      const rect = container.getBoundingClientRect();
      mouseRef.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
        active: true,
      };
    };
    const onLeave = () => {
      mouseRef.current.active = false;
    };
    const onClick = (e: MouseEvent) => {
      if (!enablePop) return;
      const rect = container.getBoundingClientRect();
      const cx = e.clientX - rect.left;
      const cy = e.clientY - rect.top;
      bubblesRef.current.forEach((b) => {
        const dx = b.x - cx;
        const dy = b.y - cy;
        if (Math.sqrt(dx * dx + dy * dy) < b.radius * 1.4 && !b.popped) {
          b.popped = true;
        }
      });
    };

    container.addEventListener("mousemove", onMove);
    container.addEventListener("mouseleave", onLeave);
    container.addEventListener("click", onClick);
    return () => {
      container.removeEventListener("mousemove", onMove);
      container.removeEventListener("mouseleave", onLeave);
      container.removeEventListener("click", onClick);
    };
  }, [mouseInteraction, enablePop]);

  // ── Draw bubble ─────────────────────────────────────────────────────────
  const drawBubble = useCallback(
    (ctx: CanvasRenderingContext2D, b: Bubble, t: number) => {
      if (b.popped) {
        // Pop burst — ring expanding
        const p = b.popProgress;
        const r = b.radius * (1 + p * 1.6);
        ctx.save();
        ctx.globalAlpha = (1 - p) * b.opacity * 1.2;
        ctx.beginPath();
        ctx.arc(b.x, b.y, r, 0, Math.PI * 2);
        ctx.strokeStyle = b.color;
        ctx.lineWidth = lerp(3, 0.5, p);
        ctx.stroke();
        // Spray dots
        for (let i = 0; i < 7; i++) {
          const angle = (i / 7) * Math.PI * 2 + p * 2;
          const dist = r * 0.9 * p;
          const sx = b.x + Math.cos(angle) * dist;
          const sy = b.y + Math.sin(angle) * dist;
          ctx.beginPath();
          ctx.arc(sx, sy, lerp(3, 0.5, p), 0, Math.PI * 2);
          ctx.fillStyle = b.color;
          ctx.fill();
        }
        ctx.restore();
        return;
      }

      const shimmer = Math.sin(t * 1.6 + b.shimmerOffset);
      const wobbleX = Math.sin(t * 0.9 + b.phase) * b.wobble * 0.1;

      // Glow
      if (enableGlow && b.glowIntensity > 0) {
        ctx.save();
        ctx.globalAlpha = b.opacity * 0.35;
        const glowGrad = ctx.createRadialGradient(
          b.x + wobbleX,
          b.y,
          b.radius * 0.1,
          b.x + wobbleX,
          b.y,
          b.radius + b.glowIntensity
        );
        glowGrad.addColorStop(0, b.color);
        glowGrad.addColorStop(1, "transparent");
        ctx.fillStyle = glowGrad;
        ctx.beginPath();
        ctx.arc(
          b.x + wobbleX,
          b.y,
          b.radius + b.glowIntensity,
          0,
          Math.PI * 2
        );
        ctx.fill();
        ctx.restore();
      }

      ctx.save();
      ctx.globalAlpha = clamp(b.opacity * (0.8 + shimmer * 0.2), 0, 1);

      // Main bubble body
      const bodyGrad = ctx.createRadialGradient(
        b.x + wobbleX - b.radius * 0.3,
        b.y - b.radius * 0.3,
        b.radius * 0.05,
        b.x + wobbleX,
        b.y,
        b.radius
      );
      bodyGrad.addColorStop(0, `hsla(${b.hue}, ${saturation}%, 95%, 0.9)`);
      bodyGrad.addColorStop(0.35, `${b.color}`);
      bodyGrad.addColorStop(0.75, `hsla(${b.hue + 20}, ${saturation}%, ${lightness - 15}%, 0.85)`);
      bodyGrad.addColorStop(1, `hsla(${b.hue + 40}, ${saturation}%, ${lightness - 25}%, 0.5)`);

      ctx.fillStyle = bodyGrad;
      ctx.beginPath();
      ctx.arc(b.x + wobbleX, b.y, b.radius, 0, Math.PI * 2);
      ctx.fill();

      // Rim highlight
      ctx.strokeStyle = `hsla(${b.hue}, ${saturation}%, 95%, ${0.3 + shimmer * 0.15})`;
      ctx.lineWidth = clamp(b.radius * 0.07, 0.5, 2.5);
      ctx.stroke();

      // Inner specular highlight
      const specR = b.radius * 0.38;
      const specGrad = ctx.createRadialGradient(
        b.x + wobbleX - b.radius * 0.28,
        b.y - b.radius * 0.35,
        0,
        b.x + wobbleX - b.radius * 0.28,
        b.y - b.radius * 0.35,
        specR
      );
      specGrad.addColorStop(0, `rgba(255,255,255,${0.7 + shimmer * 0.15})`);
      specGrad.addColorStop(0.6, `rgba(255,255,255,0.12)`);
      specGrad.addColorStop(1, `rgba(255,255,255,0)`);
      ctx.globalAlpha = 1;
      ctx.fillStyle = specGrad;
      ctx.beginPath();
      ctx.arc(
        b.x + wobbleX - b.radius * 0.28,
        b.y - b.radius * 0.35,
        specR,
        0,
        Math.PI * 2
      );
      ctx.fill();

      // Bottom reflection
      const refGrad = ctx.createRadialGradient(
        b.x + wobbleX + b.radius * 0.2,
        b.y + b.radius * 0.5,
        0,
        b.x + wobbleX + b.radius * 0.2,
        b.y + b.radius * 0.5,
        b.radius * 0.25
      );
      refGrad.addColorStop(0, `rgba(255,255,255,0.18)`);
      refGrad.addColorStop(1, `rgba(255,255,255,0)`);
      ctx.fillStyle = refGrad;
      ctx.beginPath();
      ctx.arc(
        b.x + wobbleX + b.radius * 0.2,
        b.y + b.radius * 0.5,
        b.radius * 0.25,
        0,
        Math.PI * 2
      );
      ctx.fill();

      ctx.restore();
    },
    [enableGlow, saturation, lightness]
  );

  // ── Main loop ────────────────────────────────────────────────────────────
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas || dims.w === 0 || dims.h === 0) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let running = true;
    const { w, h } = dims;

    const tick = (ts: number) => {
      if (!running) return;
      const t = ts / 1000;

      // Spawn
      if (
        t - lastSpawnRef.current > spawnInterval / 1000 &&
        bubblesRef.current.length < maxBubbles
      ) {
        bubblesRef.current.push(
          createBubble(
            w,
            h,
            colorHueStart,
            colorHueEnd,
            saturation,
            lightness,
            minRadius,
            maxRadius
          )
        );
        lastSpawnRef.current = t;
      }

      ctx.clearRect(0, 0, w, h);

      const mx = mouseRef.current.x;
      const my = mouseRef.current.y;
      const mActive = mouseRef.current.active && mouseInteraction;

      // Update + draw (back-to-front by depth)
      bubblesRef.current.sort((a, b) => a.depth - b.depth);

      bubblesRef.current = bubblesRef.current.filter((b) => {
        if (b.popped) {
          b.popProgress += 0.055;
          drawBubble(ctx, b, t);
          return b.popProgress < 1;
        }

        // Physics
        const wobble = Math.sin(t * 0.9 + b.phase) * b.wobble * 0.012;
        b.x += b.vx + wobble;
        b.y += b.vy * speed;

        // Mouse repel
        if (mActive) {
          const dx = b.x - mx;
          const dy = b.y - my;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < mouseRepelRadius && dist > 0) {
            const force = ((mouseRepelRadius - dist) / mouseRepelRadius) * 1.8;
            b.vx += (dx / dist) * force * 0.06;
            b.vy += (dy / dist) * force * 0.04;
          }
        }

        // Velocity damping + drift correction
        b.vx *= 0.978;
        b.vy = lerp(b.vy, -rand(0.5, 1.8) * (0.4 + b.depth * 0.8) * speed, 0.015);

        // Boundary bounce
        const xOff = Math.sin(t * 0.9 + b.phase) * b.wobble * 0.1;
        if (b.x + xOff < b.radius || b.x + xOff > w - b.radius) {
          b.vx *= -0.5;
        }

        // Pulse radius
        b.radius = b.baseRadius * (1 + Math.sin(t * 1.1 + b.shimmerOffset) * 0.035);

        drawBubble(ctx, b, t);

        // Remove when fully off-screen top
        return b.y + b.radius > -80;
      });

      rafRef.current = requestAnimationFrame(tick);
    };

    rafRef.current = requestAnimationFrame(tick);
    return () => {
      running = false;
      cancelAnimationFrame(rafRef.current);
    };
  }, [
    dims,
    colorHueStart,
    colorHueEnd,
    saturation,
    lightness,
    maxBubbles,
    spawnInterval,
    minRadius,
    maxRadius,
    speed,
    mouseRepelRadius,
    mouseInteraction,
    enableGlow,
    drawBubble,
  ]);

  return (
    <div
      ref={containerRef}
      className={cn("relative overflow-hidden w-full min-w-[50vw] h-full", className)}
      style={{ backgroundColor, zIndex }}
    >
      <canvas
        ref={canvasRef}
        width={dims.w}
        height={dims.h}
        className="absolute inset-0 w-full h-full pointer-events-none"
        style={{ zIndex: 0 }}
      />
      {children && (
        <div className="absolute inset-0 z-10 flex items-center justify-center">
          {children}
        </div>
      )}
    </div>
  );
};

export { AnimatedBubbleParticles };
export default AnimatedBubbleParticles;

"use client";

import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Check, Copy } from "lucide-react";
import { cn } from "@/components/lib/utils";

interface AnimatedCopyButtonProps {
  /** The text that will be copied to the clipboard */
  textToCopy: string;
  /** Optional classname for the button */
  className?: string;
  /** Size of the button */
  size?: "sm" | "md" | "lg";
  /** Optional callback fired when copied */
  onCopy?: () => void;
}

export function AnimatedCopyButton({
  textToCopy,
  className,
  size = "md",
  onCopy,
}: AnimatedCopyButtonProps) {
  const [isCopied, setIsCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(textToCopy);
      setIsCopied(true);
      if (onCopy) onCopy();

      // Reset after 2 seconds
      setTimeout(() => {
        setIsCopied(false);
      }, 2000);
    } catch (err) {
      console.error("Failed to copy text: ", err);
    }
  };

  const sizes = {
    sm: "h-8 w-8",
    md: "h-10 w-10",
    lg: "h-12 w-12",
  };

  const iconSizes = {
    sm: "h-4 w-4",
    md: "h-5 w-5",
    lg: "h-6 w-6",
  };

  return (
    <button
      onClick={handleCopy}
      className={cn(
        "relative flex items-center justify-center rounded-md border bg-background transition-colors hover:bg-muted focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        sizes[size],
        className
      )}
      aria-label="Copy to clipboard"
    >
      <AnimatePresence mode="wait" initial={false}>
        {isCopied ? (
          <motion.div
            key="check"
            initial={{ opacity: 0, scale: 0.5, rotate: -45 }}
            animate={{ opacity: 1, scale: 1, rotate: 0 }}
            exit={{ opacity: 0, scale: 0.5, rotate: 45 }}
            transition={{ type: "spring", stiffness: 300, damping: 20 }}
            className="absolute flex items-center justify-center text-green-500"
          >
            <Check className={iconSizes[size]} />
          </motion.div>
        ) : (
          <motion.div
            key="copy"
            initial={{ opacity: 0, scale: 0.5 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0, scale: 0.5 }}
            transition={{ type: "spring", stiffness: 300, damping: 20 }}
            className="absolute flex items-center justify-center text-foreground/70"
          >
            <Copy className={iconSizes[size]} />
          </motion.div>
        )}
      </AnimatePresence>
      
      {/* Background Ripple Effect on Copy */}
      {isCopied && (
        <motion.div
          initial={{ opacity: 0.5, scale: 1 }}
          animate={{ opacity: 0, scale: 2 }}
          transition={{ duration: 0.5 }}
          className="absolute inset-0 rounded-md bg-green-500/20"
        />
      )}
    </button>
  );
}

"use client";

import React, { useCallback, useEffect, useRef, useState } from "react";
import { Flipper, Flipped } from "react-flip-toolkit";
import { X } from "lucide-react";
import { cn } from "@/components/lib/utils";
import { v4 as uuidv4 } from "uuid";

export interface NotificationUser {
  avatarUrl?: string;
  name: string;
  initials?: string;
  color?: string;
}

export interface NotificationItem {
  id: string;
  user: NotificationUser;
  message: string;
  timestamp?: string;
  priority?: "low" | "medium" | "high";
  type?: "info" | "success" | "warning" | "error";
  fadingOut?: boolean;
}

export interface AnimatedNotificationProps {
  maxNotifications?: number;
  autoInterval?: number;
  autoGenerate?: boolean;
  notifications?: NotificationItem[];
  customMessages?: string[];
  animationDuration?: number;
  position?: "top-left" | "top-right" | "bottom-left" | "bottom-right" | "center";
  width?: number;
  showAvatars?: boolean;
  showTimestamps?: boolean;
  className?: string;
  onNotificationClick?: (notification: NotificationItem) => void;
  onNotificationDismiss?: (notification: NotificationItem) => void;
  allowDismiss?: boolean;
  autoDismissTimeout?: number;
  userApiEndpoint?: string;
  variant?: "default" | "minimal" | "glass" | "bordered";
  fixedUser?: NotificationUser;
}

const defaultMessages = [
  "Just completed a task! ✅",
  "New feature deployed 🚀",
  "Check out our latest update 📱",
  "Server responded with 200 OK ✨",
  "Background job finished 🔄",
  "Data synced successfully! 💾",
  "User logged in successfully 👋",
  "Payment processed 💳",
  "Email sent successfully 📧",
  "Backup completed 🛡️",
];

const Avatar: React.FC<{ user: NotificationUser; showAvatar: boolean }> = ({ user, showAvatar }) => {
  if (!showAvatar) return null;
  return (
    <div
      className="flex-shrink-0 w-10 h-10 rounded-full overflow-hidden bg-gradient-to-br from-primary/20 to-primary/40 flex items-center justify-center transition-all duration-300 hover:scale-110 backdrop-blur-sm"
      style={{ backgroundColor: user.color }}
    >
      {user.avatarUrl ? (
        <img src={user.avatarUrl} alt={`${user.name} avatar`} className="w-full h-full object-cover" loading="lazy" />
      ) : (
        <span className="text-xs font-bold text-white drop-shadow-sm">
          {user.initials || user.name.split(" ").map((n) => n[0]).join("").slice(0, 2).toUpperCase()}
        </span>
      )}
    </div>
  );
};

const Notification: React.FC<{
  notification: NotificationItem;
  showAvatars: boolean;
  showTimestamps: boolean;
  variant: string;
  onDismiss?: () => void;
  onClick?: () => void;
  allowDismiss: boolean;
}> = ({ notification, showAvatars, showTimestamps, variant, onDismiss, onClick, allowDismiss }) => {
  const getVariantStyles = () => {
    switch (variant) {
      case "minimal":
        return "bg-background/95 border border-border/50 backdrop-blur-xl";
      case "glass":
        return "bg-background/30 backdrop-blur-2xl border border-white/20 dark:border-gray-800/20 shadow-2xl";
      case "bordered":
        return "bg-card/95 border-2 border-primary/30 backdrop-blur-lg shadow-xl";
      default:
        return "bg-background/30 backdrop-blur-2xl border border-white/20 shadow-2xl";
    }
  };

  const getPriorityStyles = () => {
    switch (notification.priority) {
      case "high":
        return "border-l-4 border-l-red-500 shadow-red-500/20 dark:border-l-red-500 dark:shadow-red-500/20";
      case "medium":
        return "border-l-4 border-l-yellow-500 shadow-yellow-500/20 dark:border-l-yellow-500 dark:shadow-yellow-500/20";
      case "low":
        return "border-l-4 border-l-blue-500 shadow-[0_4px_15px_color-mix(in_srgb,var(--primarylw)_20%,transparent)] dark:border-l-blue-500 dark:shadow-[0_4px_15px_color-mix(in_srgb,var(--primarylw)_20%,transparent)]";
      default:
        return "border-l-4 border-l-primary/50 shadow-primary/20 dark:border-l-primary/50 dark:shadow-primary/20";
    }
  };

  return (
    <div
      className={cn(
        "group relative transition-all duration-500 ease-out transform hover:scale-[1.02] hover:-translate-y-1",
        "rounded-xl p-4 flex items-start gap-3 w-80 max-w-80 cursor-pointer",
        getVariantStyles(),
        getPriorityStyles(),
        notification.fadingOut && "animate-pulse"
      )}
      onClick={onClick}
    >
      <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 rounded-xl pointer-events-none" />
      <Avatar user={notification.user} showAvatar={showAvatars} />
      <div className="flex-1 min-w-0 space-y-1">
        <div className="flex items-center justify-between">
          <h3 className="font-semibold text-sm text-foreground/90 truncate">{notification.user.name}</h3>
          {showTimestamps && notification.timestamp && <span className="text-xs text-muted-foreground/70 font-mono">{notification.timestamp}</span>}
        </div>
        <p className="text-sm text-muted-foreground/80 line-clamp-2 leading-relaxed">{notification.message}</p>
      </div>

      {allowDismiss && (
        <button
          onClick={(e) => {
            e.stopPropagation();
            onDismiss?.();
          }}
          className="flex-shrink-0 w-5 h-5 text-muted-foreground/50 hover:text-muted-foreground transition-all duration-200 hover:scale-110 opacity-0 group-hover:opacity-100"
          aria-label="dismiss notification"
        >
          <X className="w-4 h-4" />
        </button>
      )}
    </div>
  );
};

async function fetchRandomUser(apiEndpoint?: string): Promise<NotificationUser> {
  try {
    const endpoint = apiEndpoint || "https://randomuser.me/api/";
    const res = await fetch(endpoint);
    const data = await res.json();
    const user = data.results[0];
    return {
      avatarUrl: user.picture?.large,
      name: `${user.name.first} ${user.name.last}`,
      color: `hsl(${Math.floor(Math.random() * 360)}, 70%, 80%)`,
    };
  } catch (error) {
    const names = ["John Doe", "Jane Smith", "Alex Johnson", "Sarah Wilson", "Mike Brown"];
    const randomName = names[Math.floor(Math.random() * names.length)];
    return {
      name: randomName,
      color: `hsl(${Math.floor(Math.random() * 360)}, 70%, 80%)`,
    };
  }
}

function getRandomMessage(customMessages?: string[]) {
  const messages = customMessages || defaultMessages;
  return messages[Math.floor(Math.random() * messages.length)];
}

async function generateNotification(customMessages?: string[], userApiEndpoint?: string, fixedUser?: NotificationUser): Promise<NotificationItem> {
  const user = fixedUser || await fetchRandomUser(userApiEndpoint);
  return {
    id: uuidv4(),
    user,
    message: getRandomMessage(customMessages),
    timestamp: new Date().toLocaleTimeString(),
    priority: (["low", "medium", "high"] as const)[Math.floor(Math.random() * 3)],
  };
}

const AnimatedNotification: React.FC<AnimatedNotificationProps> = ({
  maxNotifications = 3,
  autoInterval = 3500,
  autoGenerate = true,
  notifications = [],
  customMessages,
  animationDuration = 800,
  position = "center",
  width = 320,
  showAvatars = true,
  showTimestamps = true,
  className,
  onNotificationClick,
  onNotificationDismiss,
  allowDismiss = true,
  autoDismissTimeout = 3000,
  userApiEndpoint,
  variant = "glass",
  fixedUser,
}) => {
  const [notes, setNotes] = useState<NotificationItem[]>(notifications);
  const intervalRef = useRef<number | null>(null);
  const dismissTimeouts = useRef<Map<string, number>>(new Map());
  const isGenerating = useRef(false);

  // Helper: Clear a per-note timeout
  const clearNoteTimeout = useCallback((id: string) => {
    const t = dismissTimeouts.current.get(id);
    if (t) {
      window.clearTimeout(t);
      dismissTimeouts.current.delete(id);
    }
  }, []);

  // Dismiss with fade + removal after animationDuration
  const dismissNotification = useCallback(
    (id: string, isAutoRemoval = false) => {
      setNotes((prev) => {
        const note = prev.find((n) => n.id === id);
        if (!note || note.fadingOut) return prev;

        // mark fading out
        const updated = prev.map((n) => (n.id === id ? { ...n, fadingOut: true } : n));
        // clear any auto timeout
        clearNoteTimeout(id);

        // remove after animation
        window.setTimeout(() => {
          setNotes((current) => {
            const remaining = current.filter((n) => n.id !== id);
            // only call onNotificationDismiss if the note actually existed before removal
            if (note && onNotificationDismiss) {
              // isAutoRemoval true indicates it was auto-dismissed; user can still be notified if needed
              onNotificationDismiss(note);
            }
            return remaining;
          });
        }, animationDuration);

        return updated;
      });
    },
    [animationDuration, clearNoteTimeout, onNotificationDismiss]
  );

  // Add a new note (from generator). Ensures we don't create concurrency issues.
  const addGeneratedNote = useCallback(async () => {
    if (!autoGenerate) return;
    if (isGenerating.current) return;
    isGenerating.current = true;
    try {
      const newNote = await generateNotification(customMessages, userApiEndpoint, fixedUser);

      setNotes((prev) => {
        // prune: if there are >= maxNotifications non-fading notes, dismiss the oldest non-fading
        const nonFading = prev.filter((n) => !n.fadingOut);
        if (nonFading.length >= maxNotifications) {
          const oldest = nonFading[0];
          // gracefully mark it for fading and schedule removal using existing dismissNotification
          // call dismissNotification (which will clear its timeout and run onNotificationDismiss)
          // but to avoid calling setNotes nested while in this setNotes, we will mark it locally:
          const locallyUpdated = prev.map((n) => (n.id === oldest.id ? { ...n, fadingOut: true } : n));
          // schedule actual removal outside this setNotes by using setTimeout
          window.setTimeout(() => {
            setNotes((current) => current.filter((n) => n.id !== oldest.id));
            clearNoteTimeout(oldest.id);
            onNotificationDismiss?.(oldest);
          }, animationDuration);
          // Also clear any auto timeout for that oldest note
          const t = dismissTimeouts.current.get(oldest.id);
          if (t) {
            window.clearTimeout(t);
            dismissTimeouts.current.delete(oldest.id);
          }
          // then append the new note
          const appended = [...locallyUpdated, newNote];
          // schedule auto-dismiss for newNote
          if (autoDismissTimeout > 0) {
            const timeoutId = window.setTimeout(() => dismissNotification(newNote.id, true), autoDismissTimeout);
            dismissTimeouts.current.set(newNote.id, timeoutId);
          }
          return appended;
        } else {
          const appended = [...prev, newNote];
          if (autoDismissTimeout > 0) {
            const timeoutId = window.setTimeout(() => dismissNotification(newNote.id, true), autoDismissTimeout);
            dismissTimeouts.current.set(newNote.id, timeoutId);
          }
          return appended;
        }
      });
    } finally {
      isGenerating.current = false;
    }
  }, [
    autoGenerate,
    customMessages,
    userApiEndpoint,
    maxNotifications,
    animationDuration,
    autoDismissTimeout,
    dismissNotification,
    onNotificationDismiss,
    clearNoteTimeout,
    fixedUser,
  ]);

  // Start/stop the interval generator
  useEffect(() => {
    // If autoGenerate enabled, start interval. We'll call addGeneratedNote every autoInterval.
    if (autoGenerate) {
      // start with a small delay so UI can mount
      intervalRef.current = window.setInterval(() => {
        void addGeneratedNote();
      }, autoInterval);

      // do a first immediate call after small delay (not instant) so initial experience is consistent
      const first = window.setTimeout(() => void addGeneratedNote(), 900);

      return () => {
        if (intervalRef.current) {
          window.clearInterval(intervalRef.current);
          intervalRef.current = null;
        }
        window.clearTimeout(first);
      };
    } else {
      // autoGenerate disabled -> ensure no interval running
      if (intervalRef.current) {
        window.clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [autoGenerate, autoInterval, addGeneratedNote]);

  // Sync external notifications prop if the parent supplies them
  useEffect(() => {
    if (notifications && notifications.length > 0) {
      // clear existing timers
      dismissTimeouts.current.forEach((t) => window.clearTimeout(t));
      dismissTimeouts.current.clear();
      setNotes(notifications);
      // set up auto dismiss for those if needed
      if (autoDismissTimeout > 0) {
        notifications.forEach((n) => {
          const id = window.setTimeout(() => dismissNotification(n.id, true), autoDismissTimeout);
          dismissTimeouts.current.set(n.id, id);
        });
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [notifications]);

  // cleanup all timers on unmount
  useEffect(() => {
    return () => {
      if (intervalRef.current) window.clearInterval(intervalRef.current);
      dismissTimeouts.current.forEach((t) => window.clearTimeout(t));
      dismissTimeouts.current.clear();
    };
  }, []);

  // Manual dismiss wrapper so the caller's onNotificationDismiss isn't called twice
  const handleManualDismiss = useCallback(
    (note: NotificationItem) => {
      // clear timeout and fade out
      clearNoteTimeout(note.id);
      // mark fading and remove after animationDuration
      setNotes((prev) => prev.map((n) => (n.id === note.id ? { ...n, fadingOut: true } : n)));
      window.setTimeout(() => {
        setNotes((current) => {
          const filtered = current.filter((n) => n.id !== note.id);
          onNotificationDismiss?.(note);
          return filtered;
        });
      }, animationDuration);
    },
    [animationDuration, clearNoteTimeout, onNotificationDismiss]
  );

  const getPositionStyles = () => {
    switch (position) {
      case "top-left":
        return "fixed top-6 left-6 z-50";
      case "top-right":
        return "fixed top-6 right-6 z-50";
      case "bottom-left":
        return "fixed bottom-6 left-6 z-50";
      case "bottom-right":
        return "fixed bottom-6 right-6 z-50";
      default:
        return "flex items-center justify-center min-h-auto p-6";
    }
  };

  return (
    <>
      <style
        dangerouslySetInnerHTML={{
          __html: `
          @keyframes notification-enter {
            from {
              opacity: 0;
              transform: translateY(20px) scale(0.95);
              filter: blur(4px);
            }
            to {
              opacity: 1;
              transform: translateY(0) scale(1);
              filter: blur(0px);
            }
          }

          @keyframes notification-exit {
            from {
              opacity: 1;
              transform: translateY(0) scale(1);
              filter: blur(0px);
            }
            to {
              opacity: 0;
              transform: translateY(-20px) scale(0.95);
              filter: blur(4px);
            }
          }

          .notification-enter {
            animation: notification-enter var(--animation-duration) cubic-bezier(0.4, 0, 0.2, 1) forwards;
          }

          .notification-exit {
            animation: notification-exit var(--animation-duration) cubic-bezier(0.4, 0, 0.2, 1) forwards;
          }
        `,
        }}
      />

      <div className={cn(getPositionStyles(), className)}>
        <Flipper flipKey={notes.map((n) => n.id).join("")}>
          <div className="flex flex-col gap-4 items-center" style={{ width }}>
            {notes.map((note) => (
              <Flipped key={note.id} flipId={note.id}>
                <div
                  className={cn("notification-item", note.fadingOut ? "notification-exit" : "notification-enter")}
                  style={{ ["--animation-duration" as any]: `${animationDuration}ms` } as React.CSSProperties}
                >
                  <Notification
                    notification={note}
                    showAvatars={showAvatars}
                    showTimestamps={showTimestamps}
                    variant={variant}
                    allowDismiss={allowDismiss}
                    onClick={() => onNotificationClick?.(note)}
                    onDismiss={() => handleManualDismiss(note)}
                  />
                </div>
              </Flipped>
            ))}
          </div>
        </Flipper>
      </div>
    </>
  );
};

