"use client";

import React, { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Sun, Moon, Cloud, Star } from "lucide-react";
import { cn } from "@/components/lib/utils";

interface CoolThemeToggleProps {
  className?: string;
  size?: "sm" | "md" | "lg";
}

export function CoolThemeToggle({ className, size = "md" }: CoolThemeToggleProps) {
  const [theme, setTheme] = useState<"light" | "dark">("light");
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
    const isDark = document.documentElement.classList.contains("dark");
    setTheme(isDark ? "dark" : "light");
    
    const observer = new MutationObserver(() => {
      setTheme(document.documentElement.classList.contains("dark") ? "dark" : "light");
    });
    observer.observe(document.documentElement, { attributes: true, attributeFilter: ["class"] });
    return () => observer.disconnect();
  }, []);

  const toggleTheme = () => {
    const newTheme = theme === "light" ? "dark" : "light";
    setTheme(newTheme);
    
    if (newTheme === "dark") {
      document.documentElement.classList.add("dark");
      localStorage.setItem("theme", "dark");
    } else {
      document.documentElement.classList.remove("dark");
      localStorage.setItem("theme", "light");
    }
  };

  if (!mounted) return <div className={cn("inline-flex rounded-full bg-muted", size === "sm" ? "h-6 w-12" : size === "md" ? "h-8 w-16" : "h-10 w-20")} />;

  const sizes = {
    sm: { button: "w-12 h-6", thumb: "w-4 h-4", icon: "w-2.5 h-2.5", padding: "p-1", translateX: "translateX(24px)", cloudSize: "w-3 h-3" },
    md: { button: "w-16 h-8", thumb: "w-6 h-6", icon: "w-4 h-4", padding: "p-1", translateX: "translateX(32px)", cloudSize: "w-5 h-5" },
    lg: { button: "w-20 h-10", thumb: "w-8 h-8", icon: "w-5 h-5", padding: "p-1", translateX: "translateX(40px)", cloudSize: "w-6 h-6" }
  };

  const currentSize = sizes[size];

  return (
    <button
      onClick={toggleTheme}
      className={cn(
        "relative rounded-full transition-colors duration-500 ease-in-out focus:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-2 overflow-hidden",
        theme === "dark" ? "bg-slate-900" : "bg-sky-300",
        currentSize.button,
        currentSize.padding,
        className
      )}
      aria-label="Toggle theme"
    >
      {/* Background elements */}
      <div className="absolute inset-0 z-0 overflow-hidden rounded-full">
        <motion.div
          initial={false}
          animate={{
            opacity: theme === "light" ? 1 : 0,
            y: theme === "light" ? 0 : 10,
          }}
          transition={{ duration: 0.4 }}
          className="absolute inset-0 flex items-center justify-end pr-2 text-white"
        >
          <Cloud className={cn("text-white/80 fill-white/80", currentSize.cloudSize)} />
        </motion.div>
        
        <motion.div
          initial={false}
          animate={{
            opacity: theme === "dark" ? 1 : 0,
            y: theme === "dark" ? 0 : -10,
          }}
          transition={{ duration: 0.4 }}
          className="absolute inset-0 flex items-center justify-start pl-2"
        >
          <div className="relative w-full h-full">
            <Star className={cn("absolute top-1 left-2 text-yellow-100 fill-yellow-100 opacity-70", size === "lg" ? "w-2 h-2" : "w-1 h-1")} />
            <Star className={cn("absolute bottom-2 left-4 text-yellow-100 fill-yellow-100 opacity-50", size === "lg" ? "w-3 h-3" : "w-1.5 h-1.5")} />
            <Star className={cn("absolute top-3 left-6 text-yellow-100 fill-yellow-100 opacity-90", size === "lg" ? "w-1.5 h-1.5" : "w-1 h-1")} />
          </div>
        </motion.div>
      </div>

      {/* Toggle Thumb */}
      <motion.div
        layout
        transition={{
          type: "spring",
          stiffness: 500,
          damping: 30,
        }}
        className={cn(
          "relative z-10 flex items-center justify-center rounded-full shadow-md",
          theme === "dark" ? "bg-slate-800" : "bg-yellow-400",
          currentSize.thumb
        )}
        animate={{
          x: theme === "dark" ? parseInt(currentSize.translateX.replace("translateX(", "").replace("px)", "")) : 0
        }}
      >
        <div className="relative flex items-center justify-center w-full h-full">
          {/* Sun */}
          <motion.div
            initial={false}
            animate={{
              rotate: theme === "dark" ? 180 : 0,
              scale: theme === "dark" ? 0 : 1,
              opacity: theme === "dark" ? 0 : 1,
            }}
            transition={{ duration: 0.4 }}
            className="absolute"
          >
            <Sun className={cn("text-white fill-white/20", currentSize.icon)} />
          </motion.div>

          {/* Moon */}
          <motion.div
            initial={false}
            animate={{
              rotate: theme === "dark" ? 0 : -180,
              scale: theme === "dark" ? 1 : 0,
              opacity: theme === "dark" ? 1 : 0,
            }}
            transition={{ duration: 0.4 }}
            className="absolute flex items-center justify-center"
          >
            <Moon className={cn("text-yellow-200 fill-yellow-200", currentSize.icon)} />
          </motion.div>
        </div>
      </motion.div>
    </button>
  );
}

"use client";

import React, { useEffect, useRef, useState } from "react";

interface CosmicDustProps {
  particleCount?: number;
  speedMultiplier?: number;
  particleSize?: number;
  theme?: "light" | "dark" | "system";
}

interface Particle {
  x: number;
  y: number;
  vx: number;
  vy: number;
  size: number;
  color: string;
  opacity: number;
  history: { x: number; y: number }[];
}

export default function CosmicDust({
  particleCount = 120,
  speedMultiplier = 1.0,
  particleSize = 1.5,
  theme = "system",
}: CosmicDustProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const mouseRef = useRef({ x: 0, y: 0, targetX: 0, targetY: 0, hasMoved: false });
  const [isDarkMode, setIsDarkMode] = useState(true);

  // Theme detection mutation observer
  useEffect(() => {
    const checkTheme = () => {
      if (theme === "system") {
        setIsDarkMode(document.documentElement.classList.contains("dark"));
      } else {
        setIsDarkMode(theme === "dark");
      }
    };

    checkTheme();

    if (theme === "system") {
      const observer = new MutationObserver(checkTheme);
      observer.observe(document.documentElement, {
        attributes: true,
        attributeFilter: ["class"],
      });
      return () => observer.disconnect();
    }
  }, [theme]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let animationId: number;
    let width = (canvas.width = canvas.offsetWidth);
    let height = (canvas.height = canvas.offsetHeight);

    // Initialize default mouse position to center
    mouseRef.current.targetX = width / 2;
    mouseRef.current.targetY = height / 2;

    const colorsDark = [
      "rgba(34, 211, 238,", // cyan
      "rgba(168, 85, 247,", // purple
      "rgba(236, 72, 153,", // pink
      "rgba(234, 179, 8,",  // gold
    ];

    const colorsLight = [
      "rgba(99, 102, 241,", // indigo
      "rgba(139, 92, 246,", // violet
      "rgba(244, 63, 94,",  // rose
      "rgba(16, 185, 129,", // emerald
    ];

    // Helper to create a single particle
    const createParticle = (initRandom = false): Particle => {
      const pX = initRandom ? Math.random() * width : Math.random() * width;
      const pY = initRandom ? Math.random() * height : height + 10;
      
      const pColorSet = isDarkMode ? colorsDark : colorsLight;
      const baseColor = pColorSet[Math.floor(Math.random() * pColorSet.length)];

      return {
        x: pX,
        y: pY,
        vx: (Math.random() - 0.5) * 1.2 * speedMultiplier,
        vy: (-Math.random() - 0.2) * 1.5 * speedMultiplier,
        size: (Math.random() * 0.8 + 0.6) * particleSize,
        color: baseColor,
        opacity: Math.random() * 0.4 + 0.4,
        history: [],
      };
    };

    let particles: Particle[] = Array.from({ length: particleCount }, () => createParticle(true));

    // Handle resize
    const handleResize = () => {
      if (!canvas) return;
      width = canvas.width = canvas.offsetWidth;
      height = canvas.height = canvas.offsetHeight;
    };
    window.addEventListener("resize", handleResize);

    // Track mouse
    const handleMouseMove = (e: MouseEvent) => {
      const rect = canvas.getBoundingClientRect();
      mouseRef.current.targetX = e.clientX - rect.left;
      mouseRef.current.targetY = e.clientY - rect.top;
      mouseRef.current.hasMoved = true;
    };
    window.addEventListener("mousemove", handleMouseMove);

    // Frame Loop
    const animate = (t: number) => {
      animationId = requestAnimationFrame(animate);

      // Clear canvas (fully transparent)
      ctx.clearRect(0, 0, width, height);

      // Interpolate mouse coordinates
      if (!mouseRef.current.hasMoved) {
        // Idle animation: soft circle orbit in the center
        const cx = width / 2;
        const cy = height / 2;
        const radius = Math.min(width, height) * 0.15;
        mouseRef.current.targetX = cx + Math.cos(t * 0.001) * radius;
        mouseRef.current.targetY = cy + Math.sin(t * 0.001) * radius;
      }

      mouseRef.current.x += (mouseRef.current.targetX - mouseRef.current.x) * 0.08;
      mouseRef.current.y += (mouseRef.current.targetY - mouseRef.current.y) * 0.08;

      const mX = mouseRef.current.x;
      const mY = mouseRef.current.y;

      particles.forEach((p, index) => {
        // Natural drift
        p.vx += Math.sin(t * 0.002 + index) * 0.02 * speedMultiplier;

        // Interaction Vortex/Gravity Field
        const dx = mX - p.x;
        const dY = mY - p.y;
        const dist = Math.sqrt(dx * dx + dY * dY);
        const influenceRadius = 180;

        if (dist < influenceRadius) {
          const force = (1.0 - dist / influenceRadius) * 0.8 * speedMultiplier;
          
          // Pull force towards mouse
          p.vx += (dx / dist) * force * 0.04;
          p.vy += (dY / dist) * force * 0.04;

          // Tangential Vortex swirl force
          const swirlAngle = 0.5 * Math.PI; // Tangent direction
          const tx = -dY / dist;
          const ty = dx / dist;
          
          p.vx += tx * force * 0.18;
          p.vy += ty * force * 0.18;
        }

        // Apply friction/drag
        p.vx *= 0.96;
        p.vy *= 0.96;

        // Apply velocities
        p.x += p.vx;
        p.y += p.vy;

        // Store trail history
        p.history.push({ x: p.x, y: p.y });
        if (p.history.length > 6) {
          p.history.shift();
        }

        // Check bounds (reset if offscreen)
        if (p.y < -10 || p.x < -10 || p.x > width + 10) {
          particles[index] = createParticle(false);
          return;
        }

        // Draw particle trail
        if (p.history.length > 1) {
          ctx.beginPath();
          ctx.moveTo(p.history[0].x, p.history[0].y);
          for (let i = 1; i < p.history.length; i++) {
            ctx.lineTo(p.history[i].x, p.history[i].y);
          }
          
          ctx.strokeStyle = `${p.color}${p.opacity * 0.35})`;
          ctx.lineWidth = p.size * 0.6;
          ctx.lineCap = "round";
          ctx.stroke();
        }

        // Draw particle core
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size, 0, Math.PI * 2);
        
        if (isDarkMode) {
          ctx.shadowBlur = 5;
          ctx.shadowColor = `${p.color}0.8)`;
        } else {
          ctx.shadowBlur = 0;
        }

        ctx.fillStyle = `${p.color}${p.opacity})`;
        ctx.fill();
        ctx.shadowBlur = 0; // reset shadow for performance
      });
    };

    animationId = requestAnimationFrame(animate);

    return () => {
      cancelAnimationFrame(animationId);
      window.removeEventListener("resize", handleResize);
      window.removeEventListener("mousemove", handleMouseMove);
    };
  }, [particleCount, speedMultiplier, particleSize, isDarkMode]);

  return <canvas ref={canvasRef} className="w-full h-full absolute inset-0 -z-10 pointer-events-none" />;
}

"use client";

import React, { useEffect, useRef } from "react";
import { useInView } from "framer-motion";
import {
  BufferAttribute,
  BufferGeometry,
  Clock,
  OrthographicCamera,
  Points,
  Scene,
  ShaderMaterial,
  Vector2,
  Vector3,
  WebGLRenderer
} from "three";

interface CosmicSingularityProps {
  particleCount?: number;   // Total particles (accretion disk + background dust)
  colorInner?: string;      // Color near singularity core (hex)
  colorOuter?: string;      // Color at outer edges of disk (hex)
  speed?: number;           // Rotation speed multiplier
  gravity?: number;         // Base gravitational pull
  interactive?: boolean;    // Enable pointer tracking
  mouseDamping?: number;    // Movement transition smoothness
  transparentBg?: boolean;  // Draw transparent canvas background
  className?: string;
}

const vertexShader = `
precision highp float;

attribute float aRadius;
attribute float aAngle;
attribute float aSpeed;
attribute float aRandom;
attribute float aSize;
attribute vec2 aAmbientPos;
attribute float aType; // 1.0 = permanent accretion disk, 0.0 = background starfield

uniform float iTime;
uniform float uSpeed;
uniform float uGravity;
uniform vec2 uSingularity;
uniform vec2 uVelocity;
uniform float uHoverActive; // 1.0 = hovered, 0.0 = spread/idle

varying vec3 vColor;
varying float vAlpha;

uniform vec3 uColorInner;
uniform vec3 uColorOuter;

void main() {
  vec2 finalPos;
  float visualDist;
  float localInfluence = 0.0;

  if (aType > 0.5) {
    // 1. Permanent Accretion Disk Particle (spreads out by default, condenses on hover)
    float orbitalSpeed = aSpeed * uSpeed * (0.95 / sqrt(max(aRadius, 0.05)));
    float angle = aAngle + iTime * orbitalSpeed;
    
    // Gravity contraction
    float r = aRadius * (1.0 - uGravity * 0.12 / (aRadius + 0.15));
    float wobble = sin(iTime * 1.5 + aRandom * 6.28) * 0.02 * aRadius;
    
    vec2 relativePos = vec2(
      cos(angle) * (r + wobble),
      sin(angle) * (r + wobble)
    );
    
    vec2 targetOrbitPos = uSingularity + relativePos;
    
    // Spread default position (ambient position with slow drift)
    vec2 p_spread = aAmbientPos;
    p_spread.x += sin(iTime * 0.07 + aRandom * 6.28) * 0.05;
    p_spread.y += cos(iTime * 0.05 + aRandom * 6.28) * 0.05;
    
    // Blend based on global hover active uniform
    finalPos = mix(p_spread, targetOrbitPos, uHoverActive);
    visualDist = mix(length(p_spread - uSingularity), r, uHoverActive);
    localInfluence = uHoverActive;
  } else {
    // 2. Interactive Background Particle (spreads out, gets pulled by gravity when cursor is close)
    vec2 p_ambient = aAmbientPos;
    
    // Ambient slow drift
    p_ambient.x += sin(iTime * 0.08 + aRandom * 6.28) * 0.04;
    p_ambient.y += cos(iTime * 0.06 + aRandom * 6.28) * 0.04;
    
    // Vector to singularity
    vec2 toSingularity = uSingularity - p_ambient;
    float dist = length(toSingularity);
    
    // Gravity pull radius
    float gravityRadius = 0.85;
    float influence = smoothstep(gravityRadius, 0.15, dist) * uHoverActive;
    localInfluence = influence;
    
    // Spin orbital mapping
    float initialAngle = atan(toSingularity.y, toSingularity.x);
    float spinSpeed = uSpeed * aSpeed * (1.4 / sqrt(max(dist, 0.08)));
    float angle = initialAngle + iTime * spinSpeed * influence;
    
    // Pull inwards
    float r_orbit = dist * (1.0 - influence * 0.4);
    vec2 orbitPos = uSingularity + vec2(cos(angle), sin(angle)) * r_orbit;
    
    finalPos = mix(p_ambient, orbitPos, influence);
    visualDist = mix(dist, r_orbit, influence);
  }

  // Velocity stretch / drag opposite of singularity motion direction
  float drag = exp(-visualDist * 1.5);
  finalPos -= uVelocity * drag * 1.2;

  // Accretion disk thermal color shift
  float colorMix = clamp(visualDist / 1.15, 0.0, 1.0);
  vec3 finalColor = mix(uColorInner, uColorOuter, colorMix);
  
  // White-hot core glow near event horizon (only when inside gravity well)
  float centerGlow = exp(-visualDist * 5.0) * localInfluence;
  finalColor = mix(finalColor, vec3(1.0, 0.97, 0.90), centerGlow * 0.9);
  
  vColor = finalColor;

  // Transparency fade near event horizon and far edge limits
  float innerFade = (aType > 0.5) ? mix(1.0, smoothstep(0.04, 0.12, visualDist), uHoverActive) : 1.0;
  float outerFade = smoothstep(2.5, 1.2, visualDist);
  
  vAlpha = innerFade * outerFade * (0.28 + 0.72 * aRandom);

  // Particle glow size (pulsates over time)
  gl_PointSize = aSize * (1.0 + centerGlow * 2.2) * (0.75 + 0.25 * sin(iTime * 2.0 + aRandom * 12.0));
  
  gl_Position = projectionMatrix * modelViewMatrix * vec4(finalPos, 0.0, 1.0);
}
`;

const fragmentShader = `
precision highp float;

varying vec3 vColor;
varying float vAlpha;

void main() {
  // Soft Gaussian-like circular particle shading
  vec2 uv = gl_PointCoord - vec2(0.5);
  float dist = length(uv);
  
  if (dist > 0.5) {
    discard;
  }
  
  float intensity = smoothstep(0.5, 0.0, dist);
  gl_FragColor = vec4(vColor, vAlpha * intensity);
}
`;

const defaultColorInner = "#ffd700"; // Glowing gold core
const defaultColorOuter = "#7a00ff"; // Violet outer ring

function hexToVec3(hex: string): Vector3 {
  let value = hex.trim();
  if (value.startsWith("#")) {
    value = value.slice(1);
  }
  let r = 255;
  let g = 255;
  let b = 255;
  if (value.length === 3) {
    r = parseInt(value[0] + value[0], 16);
    g = parseInt(value[1] + value[1], 16);
    b = parseInt(value[2] + value[2], 16);
  } else if (value.length === 6) {
    r = parseInt(value.slice(0, 2), 16);
    g = parseInt(value.slice(2, 4), 16);
    b = parseInt(value.slice(4, 6), 16);
  }
  return new Vector3(r / 255, g / 255, b / 255);
}

export default function CosmicSingularityBackground({
  particleCount = 25000,
  colorInner = defaultColorInner,
  colorOuter = defaultColorOuter,
  speed = 1.0,
  gravity = 1.0,
  interactive = true,
  mouseDamping = 0.08,
  transparentBg = true,
  className = "",
}: CosmicSingularityProps) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const isInView = useInView(containerRef);

  const targetMouseRef = useRef<Vector2>(new Vector2(0, 0));
  const currentMouseRef = useRef<Vector2>(new Vector2(0, 0));
  const lastMouseRef = useRef<Vector2>(new Vector2(0, 0));
  
  const velocityRef = useRef<Vector2>(new Vector2(0, 0));
  const currentVelocityRef = useRef<Vector2>(new Vector2(0, 0));
  
  const targetGravityRef = useRef<number>(gravity);
  const currentGravityRef = useRef<number>(gravity);
  const currentHoverActiveRef = useRef<number>(0.0);
  const isHoveredRef = useRef<boolean>(false);

  useEffect(() => {
    targetGravityRef.current = gravity;
  }, [gravity]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    let active = true;
    const scene = new Scene();

    const camera = new OrthographicCamera(-1, 1, 1, -1, 0, 1);
    camera.position.z = 1;

    const renderer = new WebGLRenderer({ antialias: true, alpha: transparentBg });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));

    if (transparentBg) {
      renderer.setClearColor(0x000000, 0);
    }

    renderer.domElement.style.width = "100%";
    renderer.domElement.style.height = "100%";
    renderer.domElement.style.display = "block";
    container.appendChild(renderer.domElement);

    // Initialize particle data structures
    const count = particleCount;
    const geometry = new BufferGeometry();

    const positions = new Float32Array(count * 3);
    const aAmbientPos = new Float32Array(count * 2);
    const aType = new Float32Array(count); // 1.0 = accretion, 0.0 = background
    const aRadius = new Float32Array(count);
    const aAngle = new Float32Array(count);
    const aSpeed = new Float32Array(count);
    const aRandom = new Float32Array(count);
    const aSize = new Float32Array(count);

    for (let i = 0; i < count; i++) {
      // Split population: 35% dense permanent accretion disk, 65% background dust starfield
      const isAccretion = Math.random() < 0.35;
      const typeVal = isAccretion ? 1.0 : 0.0;
      aType[i] = typeVal;

      let x = 0;
      let y = 0;
      let r = 0;
      let angle = 0;

      if (isAccretion) {
        // Permanent Accretion disk: power distribution clustered near singularity center
        r = Math.pow(Math.random(), 1.6) * 0.9 + 0.05;
        angle = Math.random() * Math.PI * 2;
        x = Math.cos(angle) * r;
        y = Math.sin(angle) * r;
      } else {
        // Wide-spread background dust: covers the full screen boundaries
        x = (Math.random() - 0.5) * 6.0;
        y = (Math.random() - 0.5) * 4.0;
        r = Math.sqrt(x * x + y * y);
        angle = Math.atan2(y, x);
      }

      // Populate ambient positions
      const ambientX = (Math.random() - 0.5) * 6.0;
      const ambientY = (Math.random() - 0.5) * 4.0;

      positions[i * 3] = x;
      positions[i * 3 + 1] = y;
      positions[i * 3 + 2] = 0;

      aAmbientPos[i * 2] = isAccretion ? ambientX : x;
      aAmbientPos[i * 2 + 1] = isAccretion ? ambientY : y;
      
      aRadius[i] = r;
      aAngle[i] = angle;
      aSpeed[i] = 0.5 + Math.random() * 0.8;
      aRandom[i] = Math.random();
      aSize[i] = 1.0 + Math.random() * 3.5;
    }

    geometry.setAttribute("position", new BufferAttribute(positions, 3));
    geometry.setAttribute("aAmbientPos", new BufferAttribute(aAmbientPos, 2));
    geometry.setAttribute("aType", new BufferAttribute(aType, 1));
    geometry.setAttribute("aRadius", new BufferAttribute(aRadius, 1));
    geometry.setAttribute("aAngle", new BufferAttribute(aAngle, 1));
    geometry.setAttribute("aSpeed", new BufferAttribute(aSpeed, 1));
    geometry.setAttribute("aRandom", new BufferAttribute(aRandom, 1));
    geometry.setAttribute("aSize", new BufferAttribute(aSize, 1));

    const uniforms = {
      iTime: { value: 0 },
      uSpeed: { value: speed },
      uGravity: { value: gravity },
      uSingularity: { value: new Vector2(0, 0) },
      uVelocity: { value: new Vector2(0, 0) },
      uHoverActive: { value: 0.0 },
      uColorInner: { value: hexToVec3(colorInner) },
      uColorOuter: { value: hexToVec3(colorOuter) },
    };

    const material = new ShaderMaterial({
      uniforms,
      vertexShader,
      fragmentShader,
      transparent: transparentBg,
      depthWrite: false,
      depthTest: false,
    });

    const points = new Points(geometry, material);
    scene.add(points);

    const clock = new Clock();

    const setSize = () => {
      if (!active) return;
      const width = container.clientWidth || 1;
      const height = container.clientHeight || 1;
      const aspect = width / height;

      renderer.setSize(width, height, false);
      
      // Dynamic camera updates to maintain circular shapes on aspect resize
      camera.left = -aspect;
      camera.right = aspect;
      camera.top = 1;
      camera.bottom = -1;
      camera.updateProjectionMatrix();
    };

    setSize();

    const resizeObserver = new ResizeObserver(() => {
      if (active) setSize();
    });
    resizeObserver.observe(container);

    const handlePointerMove = (event: PointerEvent) => {
      const rect = renderer.domElement.getBoundingClientRect();
      const x = event.clientX - rect.left;
      const y = event.clientY - rect.top;
      const aspect = rect.width / rect.height;

      // Map canvas pixels to normalized orthographic camera coordinates
      const mouseX = (x / rect.width) * 2 * aspect - aspect;
      const mouseY = -(y / rect.height) * 2 + 1;

      targetMouseRef.current.set(mouseX, mouseY);
      isHoveredRef.current = true;
    };

    const handlePointerLeave = () => {
      isHoveredRef.current = false;
    };

    const handlePointerDown = () => {
      targetGravityRef.current = gravity * 2.5; // Strong gravity distortion on press
    };

    const handlePointerUp = () => {
      targetGravityRef.current = gravity;
    };

    if (interactive) {
      container.addEventListener("pointermove", handlePointerMove);
      container.addEventListener("pointerleave", handlePointerLeave);
      container.addEventListener("pointerdown", handlePointerDown);
      container.addEventListener("pointerup", handlePointerUp);
    }

    let rafId = 0;
    const renderLoop = () => {
      if (!active) return;

      if (isInView) {
        const time = clock.getElapsedTime();
        uniforms.iTime.value = time;

        let targetX = 0;
        let targetY = 0;

        if (interactive && isHoveredRef.current) {
          targetX = targetMouseRef.current.x;
          targetY = targetMouseRef.current.y;
        } else {
          // Centered wandering motion when not interacting
          const wanderTime = time * 0.45;
          targetX = Math.sin(wanderTime) * 0.16;
          targetY = Math.cos(wanderTime * 2.0) * 0.08;
        }

        // Interpolate coordinates
        currentMouseRef.current.x += (targetX - currentMouseRef.current.x) * mouseDamping;
        currentMouseRef.current.y += (targetY - currentMouseRef.current.y) * mouseDamping;
        uniforms.uSingularity.value.copy(currentMouseRef.current);

        // Interpolate hover active state
        const targetHoverActive = isHoveredRef.current ? 1.0 : 0.0;
        currentHoverActiveRef.current += (targetHoverActive - currentHoverActiveRef.current) * 0.05;
        uniforms.uHoverActive.value = currentHoverActiveRef.current;

        // Calculate singularity movement velocity
        const vx = currentMouseRef.current.x - lastMouseRef.current.x;
        const vy = currentMouseRef.current.y - lastMouseRef.current.y;
        lastMouseRef.current.copy(currentMouseRef.current);

        velocityRef.current.set(vx, vy);
        currentVelocityRef.current.lerp(velocityRef.current, 0.12);
        uniforms.uVelocity.value.copy(currentVelocityRef.current);

        // Interpolate gravity
        currentGravityRef.current += (targetGravityRef.current - currentGravityRef.current) * 0.1;
        uniforms.uGravity.value = currentGravityRef.current;

        renderer.render(scene, camera);
      }

      rafId = requestAnimationFrame(renderLoop);
    };

    renderLoop();

    return () => {
      active = false;
      cancelAnimationFrame(rafId);
      resizeObserver.disconnect();

      if (interactive) {
        container.removeEventListener("pointermove", handlePointerMove);
        container.removeEventListener("pointerleave", handlePointerLeave);
        container.removeEventListener("pointerdown", handlePointerDown);
        container.removeEventListener("pointerup", handlePointerUp);
      }

      geometry.dispose();
      material.dispose();
      renderer.dispose();
      renderer.forceContextLoss();

      if (renderer.domElement.parentElement) {
        renderer.domElement.parentElement.removeChild(renderer.domElement);
      }
    };
  }, [
    particleCount,
    colorInner,
    colorOuter,
    speed,
    gravity,
    interactive,
    mouseDamping,
    transparentBg,
    isInView,
  ]);

  return (
    <div
      ref={containerRef}
      className={`absolute inset-0 w-full h-full overflow-hidden ${className}`}
      style={{
        mixBlendMode: "normal",
        pointerEvents: "auto",
      }}
    />
  );
}

import React, { useState, useEffect, useRef } from "react";
import { motion, useMotionValue, useTransform, animate } from "framer-motion";
import { cn } from "@/components/lib/utils";

// Helper function to format the number
const formatValue = (val: number, precision: number, sep: string): string => {
  return val
    .toFixed(precision)
    .replace(/\B(?=(\d{3})+(?!\d))/g, sep);
};

export interface CountUpProps {
  value: number;
  duration?: number;
  decimals?: number;
  prefix?: string;
  suffix?: string;
  easing?: "linear" | "easeIn" | "easeOut" | "easeInOut";
  separator?: string;
  interactive?: boolean;
  triggerOnView?: boolean;
  className?: string;
  numberClassName?: string;
  animationStyle?: "default" | "bounce" | "spring" | "gentle" | "energetic";
  colorScheme?: "default" | "gradient" | "primary" | "secondary" | "custom";
  customColor?: string;
  onAnimationComplete?: () => void;
}

const easingFunctions = {
  linear: [0, 0, 1, 1],
  easeIn: [0.42, 0, 1, 1],
  easeOut: [0, 0, 0.58, 1],
  easeInOut: [0.42, 0, 0.58, 1],
};

const animationStyles = {
  default: { type: "tween" },
  bounce: { type: "spring", bounce: 0.25 },
  spring: { type: "spring", stiffness: 100, damping: 10 },
  gentle: { type: "spring", stiffness: 60, damping: 15 },
  energetic: { type: "spring", stiffness: 300, damping: 20 },
};

const colorSchemes = {
  default: "text-foreground",
  gradient: "bg-clip-text text-transparent bg-gradient-to-r from-primarylw to-purple-600",
  primary: "text-primary",
  secondary: "text-secondary",
  custom: "", // use customColor
};

export function CountUp({
  value,
  duration = 2,
  decimals = 0,
  prefix = "",
  suffix = "",
  easing = "easeOut",
  separator = ",",
  interactive = false,
  triggerOnView = true,
  className,
  numberClassName,
  animationStyle = "default",
  colorScheme = "default",
  customColor,
  onAnimationComplete,
}: CountUpProps) {
  const [hasAnimated, setHasAnimated] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const count = useMotionValue(0);
  const rounded = useTransform(count, function (latest) {
    return formatValue(latest, decimals, separator);
  });

  const animationConfig = {
    ...(animationStyles[animationStyle] as any),
    ease: easingFunctions[easing],
    duration: animationStyle === "default" ? duration : undefined,
  };

  useEffect(() => {
    if (!triggerOnView) {
      animate(count.get(), value, {
        ...animationConfig,
        onUpdate: function (latest) {
          return count.set(latest);
        },
        onComplete: function () {
          setHasAnimated(true);
          if (onAnimationComplete) onAnimationComplete();
        },
      });
      return;
    }

    const observer = new IntersectionObserver(
      function ([entry]) {
        if (entry.isIntersecting && !hasAnimated) {
          animate(count.get(), value, {
            ...animationConfig,
            onUpdate: function (latest) {
              return count.set(latest);
            },
            onComplete: function () {
              setHasAnimated(true);
              if (onAnimationComplete) onAnimationComplete();
            },
          });
        }
      },
      { threshold: 0.1 }
    );

    if (containerRef.current) observer.observe(containerRef.current);

    return function () {
      return observer.disconnect();
    };
  }, [value, triggerOnView, hasAnimated]);

  useEffect(
    function () {
      if (hasAnimated || !triggerOnView) {
        animate(count.get(), value, {
          ...animationConfig,
          onUpdate: function (latest) {
            return count.set(latest);
          },
          onComplete: onAnimationComplete,
        });
      }
    },
    [value, animationConfig, hasAnimated, triggerOnView, onAnimationComplete]
  );

  const colorClass =
    colorScheme === "custom" && customColor ? "" : colorSchemes[colorScheme];

  const getHoverAnimation = function () {
    if (!interactive) return {};
    return {
      whileHover: {
        scale: 1.05,
        filter: "brightness(1.1)",
        transition: { duration: 0.2 },
      },
      whileTap: {
        scale: 0.95,
        filter: "brightness(0.95)",
        transition: { duration: 0.1 },
      },
    };
  };

  return (
    <div
      ref={containerRef}
      // Using cn directly with string literals for classes
      className={cn(
        "inline-flex items-center justify-center text-4xl font-bold text-black dark:textwhite",
        className
      )}
    >
      <motion.div
        {...getHoverAnimation()}
        className={cn("flex items-center transition-all", colorClass, numberClassName)}
        style={colorScheme === "custom" && customColor ? { color: customColor } : undefined}
      >
        {prefix && <span className="mr-1 text-foreground">{prefix}</span>}
        <motion.span className=" text-foreground">{rounded}</motion.span>
        {suffix && <span className="ml-1  text-foreground">{suffix}</span>}
      </motion.div>
    </div>
  );
}

"use client";

import React, { useEffect, useRef } from "react";
import { useInView } from "framer-motion";
import {
  Clock,
  Mesh,
  OrthographicCamera,
  PlaneGeometry,
  Scene,
  ShaderMaterial,
  Vector2,
  Vector3,
  WebGLRenderer
} from "three";

interface CyberHiveProps {
  colorGrid?: string;        // Rest state cell color (e.g. dark teal/blue)
  colorNodes?: string;       // Hover state cell color (e.g. bright green/gold)
  speed?: number;            // Breathing animation speed
  gridDensity?: number;      // Density / frequency of hexagonal tiling
  warpRadius?: number;       // Radius of cursor hover gravity swell
  warpStrength?: number;     // Physical tile scaling indentation strength
  interactive?: boolean;     // Enable mouse/touch tracking
  mouseDamping?: number;     // Pointer movement lerp speed
  parallax?: boolean;        // Parallax depth offset shifting
  parallaxStrength?: number; // Parallax translation multiplier
  transparentBg?: boolean;   // Draw transparent background (transparent empty cell gaps)
  className?: string;
}

const vertexShader = `
precision highp float;
varying vec2 vUv;
void main() {
  vUv = uv;
  gl_Position = vec4(position, 1.0);
}
`;

const fragmentShader = `
precision highp float;

varying vec2 vUv;

uniform float iTime;
uniform vec3  iResolution;
uniform float animationSpeed;

uniform vec2 iMouse;
uniform bool interactive;
uniform float warpRadius;
uniform float warpStrength;
uniform float hoverInfluence;

uniform bool parallax;
uniform float parallaxStrength;
uniform vec2 parallaxOffset;

uniform vec3 uColorGrid;
uniform vec3 uColorNodes;

uniform bool transparentBg;
uniform float uGridDensity;

// Hash helper for cell random variations
float hash(vec2 p) {
  return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453123);
}

// Distance to the boundary of a regular hexagon
float hexDist(vec2 p) {
  p = abs(p);
  float d = dot(p, normalize(vec2(1.0, 1.7320508)));
  return max(d, p.x);
}

// Hex cell coordinate mapping
struct HexInfo {
  vec2 gv;
  vec2 id;
};

HexInfo getHexInfo(vec2 uv) {
  vec2 r = vec2(1.0, 1.7320508);
  vec2 h = r / 2.0;
  
  vec2 a = mod(uv, r) - h;
  vec2 b = mod(uv - h, r) - h;
  
  if (length(a) < length(b)) {
    return HexInfo(a, uv - a);
  } else {
    return HexInfo(b, uv - h - b);
  }
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
  vec2 uv = (2.0 * fragCoord - iResolution.xy) / iResolution.y;
  
  if (parallax) {
    uv += parallaxOffset;
  }

  // Hex scaling based on resolution and density multiplier
  vec2 hexUv = uv * 3.5 * uGridDensity;
  HexInfo info = getHexInfo(hexUv);
  
  // Cursor coordinate warping
  float hover = 0.0;
  if (interactive) {
    vec2 mouseP = (2.0 * iMouse.xy - iResolution.xy) / iResolution.y;
    vec2 hexMouseP = mouseP * 3.5 * uGridDensity;
    float mouseDist = length(info.id - hexMouseP);
    hover = exp(-mouseDist * mouseDist * (1.2 / warpRadius)) * hoverInfluence;
  }
  
  // Physical scale warping on cell coordinates
  vec2 localGv = info.gv * (1.0 + hover * warpStrength * 0.28);
  float d = hexDist(localGv);
  
  // Pulse animation using unique cell ID hashes
  float cellHash = hash(info.id);
  float pulse = 0.5 + 0.5 * sin(iTime * animationSpeed * 1.6 + cellHash * 6.28);
  
  // Calculate pseudo-3D normals along hexagon borders for specular shading
  vec3 normal;
  if (d < 0.44) {
    normal = vec3(0.0, 0.0, 1.0); // Flat interior
  } else {
    // Slanted boundary normals
    vec2 dir = normalize(localGv);
    normal = normalize(mix(vec3(dir * 0.4, 0.85), vec3(0.0, 0.0, 1.0), smoothstep(0.44, 0.48, d)));
  }
  
  // Glossy specular highlight (Blinn-Phong)
  vec3 lightDir = normalize(vec3(0.4, 0.8, 1.0));
  vec3 viewDir = vec3(0.0, 0.0, 1.0);
  vec3 halfDir = normalize(lightDir + viewDir);
  float spec = pow(max(dot(normal, halfDir), 0.0), 32.0);
  
  // Shading colors
  vec3 baseCol = mix(uColorGrid, uColorNodes, hover);
  float emission = mix(0.12 * (0.4 + 0.6 * pulse), 1.0, hover);
  
  // Base tile lighting and specular reflection
  vec3 col = baseCol * emission * (0.65 + max(dot(normal, lightDir), 0.0) * 0.35) + vec3(spec * (0.3 + 0.7 * hover));
  
  // Edge border glow
  float borderRing = exp(-abs(d - 0.46) * 20.0);
  col += uColorNodes * borderRing * (0.15 + 0.85 * hover);
  
  // Alpha transparency masking
  float tileMask = smoothstep(0.48, 0.45, d);
  float alpha = clamp(tileMask * (0.2 + 0.8 * emission) + borderRing * (0.4 + 0.6 * hover), 0.0, 1.0);
  
  // Vignette
  vec2 centerUv = fragCoord / iResolution.xy;
  float vignette = 1.0 - dot(centerUv - 0.5, centerUv - 0.5) * 1.2;
  vignette = max(0.0, vignette);
  
  col *= vignette;
  alpha *= vignette;
  
  if (transparentBg) {
    fragColor = vec4(col, alpha);
  } else {
    vec3 bgCol = vec3(0.005, 0.007, 0.012) + (centerUv.y * 0.008);
    fragColor = vec4(mix(bgCol, col, alpha), 1.0);
  }
}

void main() {
  vec4 color = vec4(0.0);
  mainImage(color, gl_FragCoord.xy);
  gl_FragColor = color;
}
`;

const defaultColorGrid = "#092942";  // Sleek tech blue/gray
const defaultColorNodes = "#00f0ff"; // Glowing cyan nodes

function hexToVec3(hex: string): Vector3 {
  let value = hex.trim();
  if (value.startsWith("#")) {
    value = value.slice(1);
  }
  let r = 255;
  let g = 255;
  let b = 255;
  if (value.length === 3) {
    r = parseInt(value[0] + value[0], 16);
    g = parseInt(value[1] + value[1], 16);
    b = parseInt(value[2] + value[2], 16);
  } else if (value.length === 6) {
    r = parseInt(value.slice(0, 2), 16);
    g = parseInt(value.slice(2, 4), 16);
    b = parseInt(value.slice(4, 6), 16);
  }
  return new Vector3(r / 255, g / 255, b / 255);
}

export default function CyberHiveBackground({
  colorGrid = defaultColorGrid,
  colorNodes = defaultColorNodes,
  speed = 1.0,
  gridDensity = 1.0, // Multiplier for global hex cell density
  warpRadius = 1.0,
  warpStrength = 1.0,
  interactive = true,
  mouseDamping = 0.08,
  parallax = true,
  parallaxStrength = 0.16,
  transparentBg = true,
  className = "",
}: CyberHiveProps) {
  const containerRef = useRef<HTMLDivElement | null>(null);
  const isInView = useInView(containerRef);

  const targetMouseRef = useRef<Vector2>(new Vector2(-1000, -1000));
  const currentMouseRef = useRef<Vector2>(new Vector2(-1000, -1000));
  const targetInfluenceRef = useRef<number>(0);
  const currentInfluenceRef = useRef<number>(0);
  const targetParallaxRef = useRef<Vector2>(new Vector2(0, 0));
  const currentParallaxRef = useRef<Vector2>(new Vector2(0, 0));

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    let active = true;
    const scene = new Scene();

    const camera = new OrthographicCamera(-1, 1, 1, -1, 0, 1);
    camera.position.z = 1;

    const renderer = new WebGLRenderer({ antialias: true, alpha: transparentBg });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));

    if (transparentBg) {
      renderer.setClearColor(0x000000, 0);
    }

    renderer.domElement.style.width = "100%";
    renderer.domElement.style.height = "100%";
    renderer.domElement.style.display = "block";
    container.appendChild(renderer.domElement);

    const uniforms = {
      iTime: { value: 0 },
      iResolution: { value: new Vector3(1, 1, 1) },
      animationSpeed: { value: speed },

      iMouse: { value: new Vector2(-1000, -1000) },
      interactive: { value: interactive },
      warpRadius: { value: warpRadius },
      warpStrength: { value: warpStrength },
      hoverInfluence: { value: 0 },

      parallax: { value: parallax },
      parallaxStrength: { value: parallaxStrength },
      parallaxOffset: { value: new Vector2(0, 0) },

      uColorGrid: { value: hexToVec3(colorGrid) },
      uColorNodes: { value: hexToVec3(colorNodes) },

      transparentBg: { value: transparentBg },
      uGridDensity: { value: gridDensity },
    };

    const material = new ShaderMaterial({
      uniforms,
      vertexShader,
      fragmentShader,
      transparent: transparentBg,
      depthWrite: false,
      depthTest: false,
    });

    const geometry = new PlaneGeometry(2, 2);
    const mesh = new Mesh(geometry, material);
    scene.add(mesh);

    const clock = new Clock();

    const setSize = () => {
      if (!active) return;
      const width = container.clientWidth || 1;
      const height = container.clientHeight || 1;

      renderer.setSize(width, height, false);
      const canvasWidth = renderer.domElement.width;
      const canvasHeight = renderer.domElement.height;
      
      uniforms.iResolution.value.set(canvasWidth, canvasHeight, 1);
    };

    setSize();

    const resizeObserver = new ResizeObserver(() => {
      if (active) setSize();
    });
    resizeObserver.observe(container);

    const handlePointerMove = (event: PointerEvent) => {
      const rect = renderer.domElement.getBoundingClientRect();
      const x = event.clientX - rect.left;
      const y = event.clientY - rect.top;
      const dpr = renderer.getPixelRatio();

      targetMouseRef.current.set(x * dpr, (rect.height - y) * dpr);
      targetInfluenceRef.current = 1.0;

      if (parallax) {
        const centerX = rect.width / 2;
        const centerY = rect.height / 2;
        const offsetX = (x - centerX) / rect.width;
        const offsetY = -(y - centerY) / rect.height;
        targetParallaxRef.current.set(offsetX * parallaxStrength, offsetY * parallaxStrength);
      }
    };

    const handlePointerLeave = () => {
      targetInfluenceRef.current = 0.0;
      targetParallaxRef.current.set(0, 0);
    };

    if (interactive) {
      container.addEventListener("pointermove", handlePointerMove);
      container.addEventListener("pointerleave", handlePointerLeave);
    }

    let rafId = 0;
    const renderLoop = () => {
      if (!active) return;

      if (isInView) {
        uniforms.iTime.value = clock.getElapsedTime();

        if (interactive) {
          currentMouseRef.current.lerp(targetMouseRef.current, mouseDamping);
          uniforms.iMouse.value.copy(currentMouseRef.current);

          currentInfluenceRef.current += (targetInfluenceRef.current - currentInfluenceRef.current) * mouseDamping;
          uniforms.hoverInfluence.value = currentInfluenceRef.current;
        }

        if (parallax) {
          currentParallaxRef.current.lerp(targetParallaxRef.current, mouseDamping);
          uniforms.parallaxOffset.value.copy(currentParallaxRef.current);
        }

        renderer.render(scene, camera);
      }

      rafId = requestAnimationFrame(renderLoop);
    };

    renderLoop();

    return () => {
      active = false;
      cancelAnimationFrame(rafId);
      resizeObserver.disconnect();

      if (interactive) {
        container.removeEventListener("pointermove", handlePointerMove);
        container.removeEventListener("pointerleave", handlePointerLeave);
      }

      geometry.dispose();
      material.dispose();
      renderer.dispose();
      renderer.forceContextLoss();

      if (renderer.domElement.parentElement) {
        renderer.domElement.parentElement.removeChild(renderer.domElement);
      }
    };
  }, [
    colorGrid,
    colorNodes,
    speed,
    gridDensity,
    warpRadius,
    warpStrength,
    interactive,
    mouseDamping,
    parallax,
    parallaxStrength,
    transparentBg,
    isInView,
  ]);

  return (
    <div
      ref={containerRef}
      className={`absolute inset-0 w-full h-full overflow-hidden ${className}`}
      style={{
        mixBlendMode: "normal",
        pointerEvents: "auto",
      }}
    />
  );
}

